      "content": "const _ = require('lodash');
const problemsData = require('../../data/problems.json');

class ProblemsService {
  /**
   * Get problems filtered by difficulty, tags, and limited by count.
   * @param {Object} options
   * @param {string|Array<string>} [options.tags] - Skill tags to filter by (case-insensitive).
   * @param {string} [options.difficulty] - Difficulty filter.
   * @param {number} [options.limit] - Maximum number of problems to return.
   * @returns {Object} - { problems: Array, metadata: Object }
   */
  static getProblems({ tags, difficulty, limit } = {}) {
    let problems = problemsData;

    // Normalize and parse tags filter
    let normalizedTags = [];
    if (tags) {
      if (typeof tags === 'string') {
        // Split comma-separated string and trim
        normalizedTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
      } else if (Array.isArray(tags)) {
        normalizedTags = tags.map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0);
      }
      // Remove duplicates
      normalizedTags = _.uniq(normalizedTags);
    }

    // Filter by difficulty if provided
    if (difficulty) {
      problems = problems.filter(p => p.difficulty === difficulty);
    }

    // Filter by tags if provided
    if (normalizedTags.length > 0) {
      problems = problems.filter(problem => {
        if (!problem.tags || !Array.isArray(problem.tags)) return false;
        // Normalize problem tags to lowercase
        const problemTagsLower = problem.tags.map(t => t.toLowerCase());
        // Check if problemTagsLower includes all normalizedTags
        return normalizedTags.every(tag => problemTagsLower.includes(tag));
      });
    }

    // Sort problems by stable criteria: difficulty asc, then problemId asc
    problems = _.orderBy(problems, ['difficulty', 'problemId'], ['asc', 'asc']);

    // Apply limit if provided
    if (typeof limit === 'number' && limit >= 0) {
      problems = problems.slice(0, limit);
    }

    // Compose metadata
    const metadata = {
      count: problems.length,
      tags: normalizedTags
    };

    return { problems, metadata };
  }
}

module.exports = ProblemsService;
